async function processMessage(message) {
  validateMessageStructure(message);

  console.log(`Processing message type: ${message.type}`);

  let result;

  switch (message.type) {
    case 'user.created':
      result = await processUserCreated(message.payload);
      break;
    
    case 'user.updated':
      result = await processUserUpdated(message.payload);
      break;
    
    case 'user.deleted':
      result = await processUserDeleted(message.payload);
      break;
    
    case 'order.created':
      result = await processOrderCreated(message.payload);
      break;
    
    case 'order.updated':
      result = await processOrderUpdated(message.payload);
      break;
    
    case 'payment.processed':
      result = await processPaymentProcessed(message.payload);
      break;
    
    case 'inventory.updated':
      result = await processInventoryUpdated(message.payload);
      break;
    
    default:
      throw new Error(`Unsupported message type: ${message.type}`);
  }

  console.log(`Successfully processed message: ${message.type}`);
  return result;
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqp.connect(RABBITMQ_URL);
    console.log('Connected to RabbitMQ');

    connection.on('error', (err) => {
      console.error('RabbitMQ connection error:', err);
      process.exit(1);
    });

    connection.on('close', () => {
      console.error('RabbitMQ connection closed');
      process.exit(1);
    });

    channel = await connection.createChannel();
    console.log('Channel created');

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-max-length': 10000,
        'x-message-ttl': 86400000
      }
    });

    await channel.prefetch(10);

    console.log(`Waiting for messages in queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) {
        return;
      }

      try {
        const content = msg.content.toString();
        
        if (content.length > 1000000) {
          throw new Error('Message size exceeds maximum allowed');
        }

        let message;
        try {
          message = JSON.parse(content);
        } catch (parseError) {
          throw new Error('Invalid JSON format');
        }

        await processMessage(message);
        
        channel.ack(msg);
        console.log('Message acknowledged');

      } catch (error) {
        console.error('Error processing message:', error.message);
        
        if (msg.fields.redelivered) {
          console.log('Message already redelivered, rejecting permanently');
          channel.reject(msg, false);
        } else {
          console.log('Rejecting message for requeue');
          channel.reject(msg, true);
        }
      }
    }, {
      noAck: false
    });

  } catch (error) {
    console.error('Failed to start consumer:', error);
    if (channel) await channel.close();
    if (connection) await connection.close();
    process.exit(1);
  }
}

